class AuthorizationPolicy:
    def __init__(self):
        self.api_keys = {
            k.strip(): v.strip()
            for k, v in (
                item.split(":", 1)
                for item in os.getenv("AUTH_API_KEYS", "secret-key:default-user").split(",")
                if ":" in item
            )
        }
        self.required_header = os.getenv("AUTH_REQUIRED_HEADER", "x-api-key").lower()
        self.allowed_paths = {
            p.strip() for p in os.getenv("AUTH_ALLOW_PATHS", "/healthz,/ready").split(",") if p.strip()
        }
        self.admin_header = os.getenv("AUTH_ADMIN_HEADER", "x-admin-token").lower()
        self.admin_token = os.getenv("AUTH_ADMIN_TOKEN", "admin-secret")
        self.require_tenant = os.getenv("AUTH_REQUIRE_TENANT", "false").lower() == "true"

    def evaluate(self, request):
        headers = _header_map_from_request(request)
        path = headers.get(":path", "")
        method = headers.get(":method", "")
        host = headers.get(":authority", headers.get("host", ""))
        client_ip = _get_client_ip(request)

        logger.info(
            "authz check method=%s path=%s host=%s client_ip=%s headers=%s",
            method,
            path,
            host,
            client_ip,
            {k: headers[k] for k in sorted(headers.keys()) if k not in {"authorization", self.required_header}},
        )

        if path in self.allowed_paths:
            return _allow_response(
                {
                    "x-authz-decision": "allow",
                    "x-authz-reason": "public-path",
                }
            )

        if headers.get(self.admin_header) == self.admin_token:
            return _allow_response(
                {
                    "x-authz-decision": "allow",
                    "x-authz-role": "admin",
                    "x-authz-client-ip": client_ip or "unknown",
                }
            )

        api_key = headers.get(self.required_header)
        if not api_key:
            return _deny_response(
                http_status=401,
                body="missing credentials",
                response_headers={
                    "content-type": "text/plain",
                    "www-authenticate": 'APIKey realm="envoy-ext-authz"',
                    "x-authz-decision": "deny",
                    "x-authz-reason": "missing-api-key",
                },
            )

        user = self.api_keys.get(api_key)
        if not user:
            return _deny_response(
                http_status=403,
                body="invalid credentials",
                response_headers={
                    "content-type": "text/plain",
                    "x-authz-decision": "deny",
                    "x-authz-reason": "invalid-api-key",
                },
            )

        tenant = headers.get("x-tenant-id", "")
        if self.require_tenant and not tenant:
            return _deny_response(
                http_status=403,
                body="missing tenant",
                response_headers={
                    "content-type": "text/plain",
                    "x-authz-decision": "deny",
                    "x-authz-reason": "missing-tenant",
                },
            )

        if path.startswith("/admin"):
            role = headers.get("x-role", "")
            if role != "admin":
                return _deny_response(
                    http_status=403,
                    body="admin role required",
                    response_headers={
                        "content-type": "text/plain",
                        "x-authz-decision": "deny",
                        "x-authz-reason": "role-required",
                    },
                )

        return _allow_response(
            {
                "x-authz-decision": "allow",
                "x-authenticated-user": user,
                "x-authenticated-tenant": tenant or "none",
                "x-authz-client-ip": client_ip or "unknown",
            }
        )


class ExtAuthzServicer(external_auth_pb2_grpc.AuthorizationServicer):
    def __init__(self, policy):
        self.policy = policy

    def Check(self, request, context):
        try:
            return self.policy.evaluate(request)
        except Exception:
            logger.exception("authorization check failed")
            return _deny_response(
                http_status=500,
                body="authorization service error",
                response_headers={
                    "content-type": "text/plain",
                    "x-authz-decision": "deny",
                    "x-authz-reason": "internal-error",
                },
            )


